  ('generalpolice-94737317-moex-00182', 'generalpolice-94737317', 'generalpolice-94737317-moex-113-9b499a9f', 'sub-generalpolice-94737317-02', NULL, 'single_choice', '物理學家克希荷夫在1848年提出解決複雜電路串、並聯的方法。第一項是節點定則，電路中的任何 一節點，流入的電流等於流出的電流；第二項是迴路定則，環繞任何一個封閉迴路，通過各元件兩端 電位變化的總合為零；此二定則稱為「克希荷夫定律」。有關克希荷夫定律，下列敘述何者正確？', '["節點定則即為電路中電荷守恆的另一種描述", "節點定則即為電路的能量守恆的另一種描述", "迴路定則即為電路中電荷守恆的另一種描述", "迴路定則即為電路的質量守恆的另一種描述"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:46+00:00", "source_pdf_sha1": "76c106573e8e", "answer_pdf_sha1": "0584ea26d335", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "402", "s": "1406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "普通物理學概要與普通化學概要", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
